package com.wallet.rewards.service;

import com.wallet.rewards.config.NotificationRabbitConfig;
import com.wallet.rewards.dto.NotificationEvent;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.amqp.rabbit.core.RabbitTemplate;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.eq;
import static org.mockito.Mockito.doThrow;
import static org.mockito.Mockito.verify;

@ExtendWith(MockitoExtension.class)
class NotificationClientTest {

    @Mock
    private RabbitTemplate rabbitTemplate;

    @Test
    void sendSafe_publishesEvent() {
        NotificationClient client = new NotificationClient(rabbitTemplate);

        client.sendSafe(1L, "POINTS_EARNED", "EMAIL", "a@b.com", "earned");

        verify(rabbitTemplate).convertAndSend(
                eq(NotificationRabbitConfig.NOTIFICATION_EXCHANGE),
                eq(NotificationRabbitConfig.NOTIFICATION_ROUTING_KEY),
                any(NotificationEvent.class)
        );
    }

    @Test
    void sendSafe_swallowsRabbitErrors() {
        NotificationClient client = new NotificationClient(rabbitTemplate);
        doThrow(new RuntimeException("rabbit down")).when(rabbitTemplate)
                .convertAndSend(eq(NotificationRabbitConfig.NOTIFICATION_EXCHANGE),
                        eq(NotificationRabbitConfig.NOTIFICATION_ROUTING_KEY), any(NotificationEvent.class));

        client.sendSafe(2L, "POINTS_REDEEMED", "EMAIL", "x@y.com", "redeemed");

        verify(rabbitTemplate).convertAndSend(
                eq(NotificationRabbitConfig.NOTIFICATION_EXCHANGE),
                eq(NotificationRabbitConfig.NOTIFICATION_ROUTING_KEY),
                any(NotificationEvent.class)
        );
    }
}

package com.wallet.rewards.service;

import com.wallet.rewards.dto.WalletEvent;
import com.wallet.rewards.entity.RewardsAccount;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

import java.math.BigDecimal;

import static org.mockito.ArgumentMatchers.anyLong;
import static org.mockito.ArgumentMatchers.anyInt;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.ArgumentMatchers.eq;
import static org.mockito.Mockito.never;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;

@ExtendWith(MockitoExtension.class)
class WalletEventListenerTest {

    @Mock
    private RewardsService rewardsService;

    @Test
    void handleWalletEvent_topup_addsPoints() {
        WalletEventListener listener = new WalletEventListener(rewardsService);
        RewardsAccount account = new RewardsAccount();
        account.setTier("GOLD");

        when(rewardsService.calculateEarnPoints(new BigDecimal("200"))).thenReturn(20);
        when(rewardsService.summary(1L)).thenReturn(account);

        listener.handleWalletEvent(new WalletEvent(1L, "TOPUP", new BigDecimal("200")));

        verify(rewardsService).addPoints(eq(1L), eq(30), eq("EARN_TOPUP"));
    }

    @Test
    void handleWalletEvent_transfer_doesNothing() {
        WalletEventListener listener = new WalletEventListener(rewardsService);

        listener.handleWalletEvent(new WalletEvent(2L, "TRANSFER", new BigDecimal("100")));

        verify(rewardsService, never()).addPoints(anyLong(), anyInt(), anyString());
    }
}

# RDS Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "${var.project_name}-db-subnet-group"
  subnet_ids = aws_subnet.private[*].id

  tags = {
    Name = "${var.project_name}-db-subnet-group"
  }
}

locals {
  use_supplied_db_password = var.db_password != "" && length(trimspace(var.db_password)) >= 8
}

resource "random_password" "db_password" {
  count            = local.use_supplied_db_password ? 0 : 1
  length           = 20
  special          = true
  override_special = "!@#%^*-_=+"
}

# RDS Instance
resource "aws_db_instance" "main" {
  identifier     = "${var.project_name}-db"
  engine         = "postgres"
  engine_version = "15"
  instance_class = var.db_instance_class

  allocated_storage    = var.db_allocated_storage
  storage_type         = "gp3"
  storage_encrypted    = true

  db_name  = var.db_name
  username = var.db_username
  password = local.use_supplied_db_password ? var.db_password : random_password.db_password[0].result

  db_subnet_group_name            = aws_db_subnet_group.main.name
  vpc_security_group_ids          = [aws_security_group.rds.id]
  publicly_accessible             = false

  multi_az                  = var.db_multi_az
  backup_retention_period   = var.db_backup_retention_period
  backup_window             = "03:00-04:00"
  maintenance_window        = "mon:04:00-mon:05:00"
  skip_final_snapshot       = var.skip_final_snapshot
  final_snapshot_identifier = "${var.project_name}-db-final-snapshot"

  deletion_protection             = false
  enabled_cloudwatch_logs_exports = ["postgresql"]

  tags = {
    Name = "${var.project_name}-db"
  }
}

# Outputs
output "rds_endpoint" {
  value       = aws_db_instance.main.endpoint
  description = "RDS Endpoint"
}

output "rds_address" {
  value       = aws_db_instance.main.address
  description = "RDS Address"
}

output "rds_port" {
  value       = aws_db_instance.main.port
  description = "RDS Port"
}

output "rds_database_name" {
  value       = aws_db_instance.main.db_name
  description = "RDS Database Name"
  sensitive   = true
}

